// ─── NAVBAR ───────────────────────────────────────────────────────────────────
const NAV_LINKS =
  [
    //"Home",
    // "About", "Academics", "Achievements", "Members", "Gallery",
    // "Contact"
  ];

const PublicNav = ({ current, onNavigate, onGoToLogin }) => {
  const [menuOpen, setMenuOpen] = useState(false);
  const [theme, setTheme] = useState(() => {
    return localStorage.getItem("zenelait-theme") || "dark";
  });

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
    localStorage.setItem("zenelait-theme", theme);
    window.dispatchEvent(new CustomEvent("zenelait-theme-changed", { detail: theme }));
  }, [theme]);

  useEffect(() => {
    const handleThemeChange = (e) => {
      setTheme(e.detail);
    };
    window.addEventListener("zenelait-theme-changed", handleThemeChange);
    return () => window.removeEventListener("zenelait-theme-changed", handleThemeChange);
  }, []);

  return (
    <>
      <nav
        style={{
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          zIndex: 1000,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "0 24px",
          height: 70,
          background: T.headerBg,
          backdropFilter: "blur(24px)",
          borderBottom: `1px solid ${T.border}`,
          boxShadow: "0 4px 30px rgba(0,0,0,0.4)"
        }}
      >
        {/* Logo */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 12,
            marginLeft: 150,
            fontFamily: "Syne",
            fontSize: 20,
            fontWeight: 900,
            cursor: "pointer"
          }}
          onClick={() => onNavigate("home")}
        >
          <img src="zenlogo.png" alt="image" height={60} width={80} />
        </div>

        {/* Desktop Menu */}
        <div
          className="desktop-menu"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 28,
          }}
        >
          {NAV_LINKS.map((l) => {
            const isActive = current === l.toLowerCase();
            return (
              <button
                key={l}
                onClick={() => onNavigate(l.toLowerCase())}
                style={{
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  fontSize: 13,
                  fontWeight: 600,
                  color: isActive ? T.accent : T.text,
                  position: "relative",
                  padding: "6px 2px",
                  transition: "color 0.3s ease",
                  textTransform: "uppercase",
                  letterSpacing: "0.8px"
                }}
              >
                {l}
                {isActive && (
                  <span style={{
                    position: "absolute",
                    bottom: 0,
                    left: 0,
                    right: 0,
                    height: 2,
                    background: `linear-gradient(90deg, ${T.primary}, ${T.accent})`,
                    borderRadius: 2
                  }} />
                )}
              </button>
            );
          })}
        </div>

        {/* Actions Container */}
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          {/* Theme Toggle Button */}
          <div
            onClick={() => setTheme(prev => prev === "bright" ? "dark" : "bright")}
            style={{
              width: 36,
              height: 36,
              borderRadius: "50%",
              background: T.bg3,
              border: `1px solid ${T.border}`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              cursor: "pointer",
              fontSize: 15,
              transition: "all 0.3s ease",
              color: T.text
            }}
            onMouseEnter={e => e.currentTarget.style.borderColor = T.accent}
            onMouseLeave={e => e.currentTarget.style.borderColor = T.border}
            title={theme === "bright" ? "Switch to Dark Theme" : "Switch to Bright Theme"}
          >
            {theme === "bright" ? "☀️" : "🌙"}
          </div>

          {/* Desktop Login Button */}
          <button
            className="desktop-login"
            onClick={onGoToLogin}
            style={{
              background: `linear-gradient(135deg, ${T.primary}, ${T.primaryL})`,
              border: "none",
              color: "#fff",
              padding: "10px 24px",
              borderRadius: 50,
              fontWeight: 800,
              fontSize: 13,
              cursor: "pointer",
              boxShadow: `0 4px 14px ${T.primary}40`,
              transition: "all 0.3s ease",
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-2px)";
              e.currentTarget.style.boxShadow = `0 6px 20px ${T.primary}60`;
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "translateY(0)";
              e.currentTarget.style.boxShadow = `0 4px 14px ${T.primary}40`;
            }}
          >
            🚀 Login
          </button>

          {/* Mobile Hamburger */}
          <div
            className="mobile-menu-icon"
            onClick={() => setMenuOpen(!menuOpen)}
            style={{
              display: "none",
              fontSize: 24,
              cursor: "pointer",
              color: T.text,
            }}
          >
            ☰
          </div>
        </div>
      </nav>

      {/* Mobile Dropdown */}
      {menuOpen && (
        <div
          style={{
            position: "fixed",
            top: 70,
            left: 0,
            right: 0,
            background: T.dropdownBg,
            backdropFilter: "blur(24px)",
            padding: "24px",
            display: "flex",
            flexDirection: "column",
            gap: 18,
            zIndex: 999,
            borderBottom: `1px solid ${T.border}`
          }}
        >
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => {
                onNavigate(l.toLowerCase());
                setMenuOpen(false);
              }}
              style={{
                background: "none",
                border: "none",
                textAlign: "left",
                fontSize: 16,
                fontWeight: 600,
                color: current === l.toLowerCase() ? T.accent : T.text,
                cursor: "pointer",
              }}
            >
              {l}
            </button>
          ))}

          <button
            onClick={() => {
              onGoToLogin();
              setMenuOpen(false);
            }}
            style={{
              marginTop: 12,
              background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
              border: "none",
              color: "#fff",
              padding: "12px",
              borderRadius: 30,
              fontWeight: 700,
              cursor: "pointer",
            }}
          >
            🚀 Login / Register
          </button>
        </div>
      )}

      {/* Responsive CSS */}
      <style>
        {`
          @media (max-width: 768px) {
            .desktop-menu,
            .desktop-login {
              display: none !important;
            }

            .mobile-menu-icon {
              display: block !important;
            }
          }
        `}
      </style>
    </>
  );
};

// ─── FOOTER ───────────────────────────────────────────────────────────────────
const PublicFooter = () => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handler = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener("resize", handler);
    return () => window.removeEventListener("resize", handler);
  }, []);

  return (
    <footer style={{ background: T.bg2, borderTop: `1px solid ${T.border}`, padding: isMobile ? "48px 24px 24px" : "60px 60px 32px", marginTop: 80, position: "relative", zIndex: 5 }}>
      <div style={{
        display: "grid",
        gridTemplateColumns: isMobile ? "1fr 1fr" : "2fr 1fr 1fr 1fr",
        gap: isMobile ? 32 : 40,
        maxWidth: 1200,
        margin: "0 auto"
      }}>
        {/* Brand block — full width on mobile */}
        <div style={{ gridColumn: isMobile ? "1 / -1" : "auto" }}>
          <div style={{ fontFamily: "Syne", fontSize: 20, fontWeight: 900, marginBottom: 16 }}>
            <img src="logo.png" alt="image" height={60} width={130} style={{ borderRadius: 10 }} />
          </div>
          <p style={{ fontSize: 13, color: T.muted, lineHeight: 1.8, maxWidth: 280 }}>
            Enterprise-grade Learning Management System powering interactive education globally.
          </p>
        </div>

        {[
          { h: "Platform", l: ["Students", "Teachers", "Parents", "Admin"] },
          { h: "Company", l: ["About Us", "Team", "Awards", "Blog"] },
          { h: "Legal", l: ["Privacy Policy", "Terms", "Cookies"] },
        ].map(col => (
          <div key={col.h}>
            <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1.5, color: T.muted, marginBottom: 18 }}>
              {col.h}
            </div>
            {col.l.map(l => (
              <div key={l}
