// ─── CONTACT PAGE ─────────────────────────────────────────────────────────────
export const Contact = () => {
  const [orgs, setOrgs] = useState([]);
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    subject: "",
    message: "",
    organizationId: "",
  });

  useEffect(() => {
    getOrganizations()
      .then((data) => {
        setOrgs(Array.isArray(data) ? data : []);
      })
      .catch((err) => console.error("Failed to load organizations:", err));
  }, []);

  const f = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  const validate = () => {
    const e = {};
    if (!form.organizationId) e.organizationId = "Organization is required";
    if (!form.name.trim()) e.name = "Name is required";
    if (!form.email.trim()) e.email = "Email is required";
    else if (!form.email.includes("@")) e.email = "Enter a valid email address";
    if (!form.phone.trim()) e.phone = "Phone number is required";
    else if (form.phone.replace(/\D/g, "").length < 10)
      e.phone = "Enter a valid phone number";

    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSend = async () => {
    if (!validate()) return;
    try {
      setLoading(true);
      await submitContactMessage(form);
      setSent(true);
    } catch (err) {
      alert("Failed to send message: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = (field) => ({
    width: "100%",
    background: T.bg3,
    border: `1.5px solid ${errors[field] ? "#ef4444" : T.border}`,
    borderRadius: 10,
    padding: "12px 16px",
    fontSize: 13.5,
    color: T.text,
    outline: "none",
    fontFamily: "DM Sans",
    boxSizing: "border-box",
    transition: "border-color 0.3s ease"
  });

  const errTxt = (field) =>
    errors[field] ? (
      <div style={{ fontSize: 11, color: "#ef4444", marginTop: 6, fontWeight: 600 }}>
        ⚠ {errors[field]}
      </div>
    ) : null;

  return (
    <div className="contact-container">
      <div className="contact-header">
        <Badge type="info">Contact</Badge>
        <h2>Get In Touch</h2>
        <p>
          Need assistance? Send us a message and our administration team will follow up promptly.
        </p>
      </div>

      <div className="contact-grid">
        {/* Left Info */}
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {[
            {
              icon: Icons.target(T.accent),
              label: "Address",
              val: "Zenelait InfoTech, Anna Salai, Chennai, Tamil Nadu - 600002",
            },
            { icon: Icons.mobile(T.accent), label: "Phone", val: "+91 98765 43210" },
            { icon: Icons.chat(T.accent), label: "Email", val: "info@zenelaitinfotech.com" },
            {
              icon: Icons.briefcase(T.accent),
              label: "Office Hours",
              val: "Mon–Sat: 9:00 AM – 6:00 PM",
            },
          ].map((c, idx) => (
            <div key={idx} className="contact-info-item">
              <div className="contact-icon">{c.icon}</div>
              <div>
                <div className="contact-label">{c.label}</div>
                <div className="contact-value">{c.val}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Form */}
        <TiltCard className="contact-card" style={{ padding: 32, background: T.bg2 }}>
          <h3>Send a Message</h3>

          {!sent ? (
            <>
              <div className="field">
                <label>Organization *</label>
                <select
                  value={form.organizationId}
                  onChange={f("organizationId")}
                  style={inputStyle("organizationId")}
                >
                  <option value="" style={{ background: T.bg3, color: T.text }}>-- Select Organization --</option>
                  {orgs.map((org) => (
                    <option key={org.id} value={org.id} style={{ background: T.bg3, color: T.text }}>
                      {org.name}
                    </option>
                  ))}
                </select>
                {errTxt("organizationId")}
              </div>

              <div className="field">
                <label>Your Name *</label>
                <input
                  value={form.name}
                  onChange={f("name")}
                  placeholder="Enter your full name"
                  style={inputStyle("name")}
                />
                {errTxt("name")}
              </div>

              <div className="field">
                <label>Email Address *</label>
                <input
                  type="email"
                  value={form.email}
                  onChange={f("email")}
                  placeholder="your@email.com"
                  style={inputStyle("email")}
                />
                {errTxt("email")}
              </div>

              <div className="field">
                <label>Phone Number *</label>
                <input
                  value={form.phone}
                  onChange={f("phone")}
                  placeholder="+91 98765 43210"
                  style={inputStyle("phone")}
                />
                {errTxt("phone")}
              </div>

              <div className="field">
                <label>Subject</label>
                <input
                  value={form.subject}
                  onChange={f("subject")}
                  placeholder="What is this regarding?"
                  style={inputStyle("subject")}
                />
              </div>

              <div className="field">
                <label>Message</label>
                <textarea
                  rows={4}
                  value={form.message}
                  onChange={f("message")}
                  placeholder="Write your message here..."
                  style={{ ...inputStyle("message"), resize: "vertical" }}
                />
              </div>

              <Btn full onClick={handleSend} disabled={loading}>
                {loading ? "Sending..." : "Send Message →"}
              </Btn>
            </>
          ) : (
            <div className="success-box">
              <div className="success-icon" style={{ fontSize: 44, color: T.accentG, marginBottom: 16 }}>✓</div>
              <h3>Message Sent!</h3>
              <p style={{ color: T.muted, fontSize: 14, marginBottom: 20 }}>
                Your query has been recorded. Our administrative desk will respond shortly.
              </p>
              <Btn
                onClick={() => {
                  setForm({
                    name: "",
                    email: "",
                    phone: "",
                    subject: "",
                    message: "",
                    organizationId: "",
                  });
                  setSent(false);
                }}
              >
                Send Another
              </Btn>
            </div>
          )}
        </TiltCard>
      </div>

      <style>{`
        .contact-container {
          padding: 80px 24px;
          max-width: 1100px;
          margin: auto;
          position: relative;
        }

        .contact-header {
          text-align: center;
          margin-bottom: 50px;
        }

        .contact-header h2 {
          font-size: 40px;
          font-family: Syne;
          font-weight: 800;
          margin: 12px 0;
        }

        .contact-header p {
          font-size: 15px;
          color: ${T.muted};
        }

        .contact-grid {
          display: grid;
          grid-template-columns: 1fr 1.4fr;
          gap: 36px;
        }

        .contact-info-item {
          display: flex;
          gap: 16px;
          align-items: center;
          padding: 16px 20px;
          background: ${T.bg2};
          border: 1px solid ${T.border};
          border-radius: 12px;
          transition: all 0.3s ease;
        }
        .contact-info-item:hover {
          transform: translateX(6px);
          border-color: ${T.accent}50;
        }

        .contact-icon {
          width: 44px;
          height: 44px;
          background: ${T.accent}16;
          border-radius: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
        }

        .contact-label {
          font-weight: 700;
          font-size: 14px;
          color: ${T.text};
        }

        .contact-value {
          font-size: 13px;
          color: ${T.muted};
          margin-top: 2px;
        }

        .field {
          margin-bottom: 16px;
        }

        .field label {
          font-size: 11px;
          font-weight: 700;
          text-transform: uppercase;
          display: block;
          margin-bottom: 6px;
          color: ${T.muted};
          letter-spacing: 0.8px;
        }

        .success-box {
          text-align: center;
          padding: 30px 0;
        }

        @media (max-width: 768px) {
          .contact-container {
            padding: 40px 16px;
          }

          .contact-grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
    </div>
  );
};

